import{_ as e,o as t,c as n,O as s}from"./chunks/framework.92cbe775.js";const m=JSON.parse('{"title":"","description":"","frontmatter":{"aside":false,"outline":false,"lastUpdated":false},"headers":[],"relativePath":"en/materials/value.md","filePath":"en/materials/value.md","lastUpdated":1776068451000}'),r={name:"en/materials/value.md"};function i(l,a,o,d,c,p){return t(),n("div",null,a[0]||(a[0]=[s('<div class="brand-page-shell"><section class="brand-hero"><div><p class="brand-kicker">Value Narrative</p><h1>Value Framing</h1><div class="brand-hero__panel"><span class="brand-pill">Decision Layer</span><strong>Customers do not ultimately pay just because &quot;there is an AI page.&quot; They pay for efficiency, controllability, and a clear answer about whether the right path today is the free path, local expansion, the formal team edition, or enterprise delivery.</strong><p>If the value story is detached from the real entry path, it becomes very easy to mix up lightweight experience, standard team collaboration, and enterprise delivery.</p></div><p class="brand-lead"> Value judgment usually concentrates around the three questions decision makers ask most often: <strong>what does it actually save, how safe is it really, and is it worth trying with a real scenario now.</strong> In real conversations there is still another layer to add: whether the next step is better framed as the free path, local script-slot expansion, a formal monthly or annual team-tenant path, or direct enterprise-project evaluation. </p><div class="brand-chip-list"><span class="brand-chip">Efficiency</span><span class="brand-chip">Control</span><span class="brand-chip">Deliverability</span><span class="brand-chip">Worth trying now</span></div><div class="brand-actions"><a class="cta-button cta-button--brand" href="./pitch.html">View the Pitch</a><a class="cta-button" href="../product/customer-flow.html">View Customer Flow / Delivery</a></div></div><div class="brand-hero__media brand-hero__media--compact"><div class="matrix-panel matrix-panel--contact"><div class="matrix-panel__hud"><span>EXECGOV // VALUE NARRATIVE</span><span>MAT 03</span></div><div class="matrix-panel__canvas"><div class="matrix-panel__trace matrix-panel__trace--top"></div><div class="matrix-panel__trace matrix-panel__trace--mid"></div><div class="matrix-panel__trace matrix-panel__trace--bottom"></div><div class="matrix-panel__stack"><span class="matrix-panel__line"><span class="matrix-panel__key">save</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value matrix-panel__ident">manual_steps</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value matrix-panel__ident">repeated_handoff</span></span><span class="matrix-panel__line"><span class="matrix-panel__key">control</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value matrix-panel__string">permission</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value matrix-panel__fn">confirm</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value matrix-panel__fn">audit_trail</span></span><span class="matrix-panel__line"><span class="matrix-panel__key">grow</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value matrix-panel__ident">free_to_team</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value matrix-panel__ident">shared_saas_to_private</span></span></div><div class="matrix-panel__callout">VALUE = COST / SPEED / RISK</div></div><div class="matrix-panel__footer"><span class="matrix-panel__tag"><span class="matrix-panel__key">focus</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">efficiency</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">focus</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">control</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">focus</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">growth</span></span></div></div></div></section><section class="brand-grid brand-grid--three"><article class="brand-card"><p class="brand-kicker">Question 01</p><h2>What does it actually save for me</h2><p>It turns execution capability that used to be scattered across commands, scripts, interfaces, templates, folders, and personal know-how into one unified entry, reducing repeated work, time spent finding capability, and cross-person communication cost.</p></article><article class="brand-card"><p class="brand-kicker">Question 02</p><h2>How safe and controllable is it really</h2><p>The platform emphasizes permission boundaries, human confirmation, execution traceability, and tenant isolation. It does not let AI run freely through the system outside rules.</p></article><article class="brand-card"><p class="brand-kicker">Question 03</p><h2>Is it worth trying right now</h2><p>If scripts, interfaces, reporting work, or local workflows already exist, the platform can first connect the most painful segment into one governed entry and then let you judge whether it deserves further expansion.</p></article></section><section class="brand-card"><p class="brand-kicker">Stage Value</p><h2>The value emphasis changes by stage</h2><table><thead><tr><th>Stage</th><th>Primary value</th><th>Best way to frame it</th><th>Suggested entry</th></tr></thead><tbody><tr><td>Free path</td><td>Low-friction first contact with the platform value</td><td>Prove first that this is not a generic chat page, but a platform that can bring scripts and automation into one governed entry</td><td><a href="../guide/getting-started.html">Getting Started</a></td></tr><tr><td>Local script-slot expansion</td><td>Keep growing personal usage at low cost</td><td>Emphasize that this is fixed-package script-slot expansion, not a formal team subscription</td><td><a href="./membership-benefits-pricing.html">Membership and Pricing</a></td></tr><tr><td>Team edition monthly / annual subscription</td><td>Multi-user collaboration, formal tenants, and a more stable usage cycle</td><td>Emphasize that the formal team path is currently carried by the shared-SaaS frontend while data and permissions remain isolated by tenant</td><td><a href="../product/personal-billing-membership.html">Billing and Membership</a></td></tr><tr><td>Enterprise / private deployment</td><td>Stronger isolation, intranet access, local bridging, and formal delivery</td><td>Emphasize deployment, governance boundaries, milestones, and acceptance criteria instead of reusing the standard membership narrative</td><td><a href="../product/deployment.html">Deployment</a> / <a href="./service-packages.html">Kickoff Options / Service Packages</a></td></tr></tbody></table></section><section class="brand-grid brand-grid--two"><article class="brand-card"><p class="brand-kicker">Efficiency</p><h2>Why it actually saves time</h2><ul class="brand-list"><li>You no longer rely on people memorizing script paths and command details.</li><li>You no longer rely on a few people passing critical knowledge around verbally.</li><li>The same category of work can be repeated through one unified entry.</li><li>AI can make the &quot;find the right capability&quot; step feel much more natural.</li></ul></article><article class="brand-card"><p class="brand-kicker">Control</p><h2>Why this is not &quot;letting AI roam freely through the system&quot;</h2><ul class="brand-list"><li>The recommendation surface is constrained by tenant and permission boundaries.</li><li>High-risk actions can require human confirmation.</li><li>Execution results and records remain traceable.</li><li>Customers stay isolated by default instead of being visible to one another.</li></ul></article></section><section class="brand-card"><p class="brand-kicker">Decision View</p><h2>What different roles usually care about most</h2><table><thead><tr><th>Role</th><th>Main question</th><th>Best framing</th><th>Read next</th></tr></thead><tbody><tr><td>Business owner / decision maker</td><td>Is this worth funding, and can it become a lasting asset</td><td>Emphasize the growth path from the free path to the formal team edition and then enterprise delivery instead of making every investment heavy on day one</td><td><a href="./pitch.html">Pitch</a></td></tr><tr><td>Business lead</td><td>Can our current workflow really be connected into the platform</td><td>Emphasize the unified entry, AI recommendation, result return, and hot update, and explain when the standard team edition is enough and when enterprise delivery is the better fit</td><td><a href="../product/customer-flow.html">Customer Flow / Delivery</a></td></tr><tr><td>Technical lead</td><td>Is it controllable, will tenants leak into each other, and can it be delivered sustainably</td><td>Emphasize the boundary between shared SaaS and single-tenant delivery, tenant isolation, permission boundaries, approval and authorization, and the CLI bridge</td><td><a href="../product/architecture.html">Architecture</a></td></tr><tr><td>Delivery lead</td><td>How does ongoing update and acceptance work after launch</td><td>Emphasize customer flow, deliverables, hot update, the upgrade rhythm of shared SaaS, and the acceptance focus of enterprise projects</td><td><a href="../product/customer-flow.html">Customer Flow / Delivery</a></td></tr></tbody></table></section><section class="brand-grid brand-grid--two"><article class="brand-card"><p class="brand-kicker">One Sentence</p><h2>How to say the value in one sentence</h2><p>ExecGov is not another chat box. It helps you bring scattered and risky team scripts and automation flows into one governed entry so they run steadily, leave records behind, and stay reviewable later.</p></article><article class="brand-card"><p class="brand-kicker">Longer Version</p><h2>How to explain the value in one paragraph</h2><p>Many companies do not lack scripts, interfaces, templates, or workflows. What they truly lack is a unified entry point, permission boundaries, and the ability to keep delivering in a stable way. The value of ExecGov is turning those scattered capabilities into one governed execution platform so customers can use their own capability through a unified entry while the platform handles recommendation, confirmation, execution, and traceability inside explicit boundaries. Python scripts are still the first mature execution asset today, but the strongest way to express the value is not by listing every feature. It is by judging first whether the next step belongs to the free path, local script-slot expansion, the shared-SaaS formal tenant path, or direct enterprise delivery.</p></article></section><section class="brand-card brand-card--cta"><div class="brand-card__row"><div><p class="brand-kicker">Next Read</p><h2>After the value judgment, the next thing readers need is delivery reality</h2><p class="brand-lead">If the value story does not connect to a real delivery path, project judgment usually stops there.</p></div><div class="brand-link-grid brand-link-grid--compact"><a class="brand-link-card" href="../product/customer-flow.html"><span>Delivery</span><strong>Customer Flow / Delivery</strong></a><a class="brand-link-card" href="../product/deployment.html"><span>Deployment</span><strong>Deployment</strong></a><a class="brand-link-card" href="../product/editions.html"><span>Roadmap</span><strong>Edition Roadmap</strong></a><a class="brand-link-card" href="../contact.html#lead-form"><span>Lead</span><strong>Discuss a real scenario</strong></a></div></div></section></div>',1)]))}const u=e(r,[["render",i]]);export{m as __pageData,u as default};
